76	                       BytecodeVersionParser>
77	      bytecodeVersion("bytecode-version",
78	                      llvm::cl::desc("Bytecode version to use for translation"),
79	                      llvm::cl::init(BytecodeVersion::kCurrentVersion));
80	
81	  bytecodeVersionPtr = &bytecodeVersion;
82	}
