95	      llvm::cl::location(warnUnsupportedHintsVar), llvm::cl::init(false));
96	
97	  static llvm::cl::opt<bool, true> errorOnHints(
98	      "Werr-hints",
99	      llvm::cl::desc("Treat unsupported/invalid optimization hints as errors."),
100	      llvm::cl::location(errorUnsupportedHintsVar), llvm::cl::init(false));
101	}
