103	bool mlir::cuda_tile::getWarnUnsupportedHints() {
104	  return warnUnsupportedHintsVar;
105	}
106	
107	bool mlir::cuda_tile::getErrorUnsupportedHints() {
108	  return errorUnsupportedHintsVar;
109	}
