111	void mlir::cuda_tile::registerListVersionsOption() {
112	  static llvm::cl::opt<bool> listVersions(
113	      "list-versions",
114	      llvm::cl::desc("List all supported bytecode versions and exit"),
115	      llvm::cl::init(false), llvm::cl::callback([](const bool &val) {
116	        if (val) {
117	          auto versions = getSupportedVersions();
118	          for (const auto &version : versions)
119	            llvm::outs() << version.toString() << "\n";
120	          exit(0);
121	        }
122	      }));
123	}
