    /*verMajor=*/13,
    /*verMinor=*/3,
    /*verTag=*/0,
};

/// The lowest supported version of the bytecode format.
const BytecodeVersion BytecodeVersion::kMinSupportedVersion = {
    /*verMajor=*/13,
    /*verMinor=*/1,
    /*verTag=*/0,
};

//===----------------------------------------------------------------------===//
// Opcode Version Checking
